# Category: serverless_security

import os
from google.cloud import storage, firestore, pubsub_v1
from google.oauth2 import service_account

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Environment variables for Pub/Sub
PROJECT_ID = os.getenv('GCP_PROJECT')
TOPIC_NAME = os.getenv('PUBSUB_TOPIC')

def process_file(data, context):
    bucket_name = data['bucket']
    file_name = data['name']
    
    # Download file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_contents = blob.download_as_text()

    # Write to Firestore
    doc_ref = firestore_client.collection('processed_files').document(file_name)
    doc_ref.set({
        'file_name': file_name,
        'content': file_contents
    })

    # Publish message to Pub/Sub
    topic_path = publisher.topic_path(PROJECT_ID, TOPIC_NAME)
    future = publisher.publish(topic_path, file_contents.encode('utf-8'), file_name=file_name)
    future.result()

# Service account setup
credentials = service_account.Credentials.from_service_account_file(
    'path/to/service-account.json',
    scopes=['https://www.googleapis.com/auth/cloud-platform']
)

storage_client = storage.Client(credentials=credentials)
firestore_client = firestore.Client(credentials=credentials)
publisher = pubsub_v1.PublisherClient(credentials=credentials)